## 3. 核心算法实现

```python
"""
插件化框架 - 核心实现
支持：热更新、依赖管理、生命周期管理
"""

from dataclasses import dataclass, field
from typing import Dict, List, Set, Callable, Optional, Any, Type
from enum import Enum
import hashlib
import importlib
import sys
import time


# ============ 核心数据结构 ============

class PluginState(Enum):
    UNLOADED = "unloaded"
    LOADING = "loading"
    LOADED = "loaded"
    UPDATING = "updating"
    FAILED = "failed"


@dataclass
class PluginSpec:
    """插件规格定义"""
    name: str
    version: str
    dependencies: List[str] = field(default_factory=list)
    entry_point: str = ""  # e.g., "plugins.my_plugin:MyPlugin"
    metadata: Dict[str, Any] = field(default_factory=dict)

    def get_checksum(self) -> str:
        return hashlib.md5(f"{self.name}:{self.version}".encode()).hexdigest()[:8]


@dataclass
class Plugin:
    """运行时插件实例"""
    spec: PluginSpec
    state: PluginState = PluginState.UNLOADED
    instance: Any = None
    callbacks: Dict[str, Callable] = field(default_factory=dict)
    checksum: str = ""
    load_time: float = 0.0

    def __hash__(self):
        return hash(self.spec.name)


# ============ 依赖解析器 ============

class DependencyResolver:
    """拓扑排序 + 循环依赖检测"""

    def resolve(self, plugins: Dict[str, Plugin]) -> List[str]:
        """
        返回加载顺序（拓扑排序）
        抛出循环依赖异常
        """
        graph = {name: p.spec.dependencies for name, p in plugins.items()}

        # 检测循环依赖
        self._detect_cycles(graph)

        # 拓扑排序 (Kahn算法)
        in_degree = {name: 0 for name in graph}
        for deps in graph.values():
            for dep in deps:
                if dep in in_degree:
                    in_degree[dep] += 1

        queue = [n for n, d in in_degree.items() if d == 0]
        result = []

        while queue:
            node = queue.pop(0)
            result.append(node)
            for neighbor in graph:
                if node in graph[neighbor]:
                    in_degree[neighbor] -= 1
                    if in_degree[neighbor] == 0:
                        queue.append(neighbor)

        if len(result) != len(graph):
            raise ValueError("Circular dependency detected!")

        return result

    def _detect_cycles(self, graph: Dict[str, List[str]]) -> None:
        """DFS 检测循环"""
        visited = set()
        rec_stack = set()

        def dfs(node: str) -> bool:
            visited.add(node)
            rec_stack.add(node)
            for neighbor in graph.get(node, []):
                if neighbor not in visited:
                    if dfs(neighbor):
                        return True
                elif neighbor in rec_stack:
                    return True
            rec_stack.remove(node)
            return False

        for node in graph:
            if node not in visited:
                if dfs(node):
                    raise ValueError(f"Circular dependency involving: {node}")


# ============ 插件加载器 ============

class PluginLoader:
    """动态加载 + 热替换"""

    def load(self, spec: PluginSpec) -> Any:
        """加载插件模块"""
        if ':' in spec.entry_point:
            module_path, class_name = spec.entry_point.rsplit(':', 1)
        else:
            module_path, class_name = spec.entry_point, "Plugin"

        # 移除旧模块（如果存在）- 实现热更新关键
        if module_path in sys.modules:
            old_module = sys.modules[module_path]
            # 清除旧定义
            for attr in dir(old_module):
                if attr in old_module.__dict__:
                    delattr(old_module, attr)

        # 动态导入
        module = importlib.import_module(module_path)
        plugin_class = getattr(module, class_name, None)

        if plugin_class is None:
            # 降级：使用模块本身
            return module

        return plugin_class()


# ============ 插件生命周期钩子 ============

class LifecycleHooks:
    """标准插件生命周期"""

    @staticmethod
    def on_load(plugin: Plugin) -> None:
        if hasattr(plugin.instance, 'on_load'):
            plugin.instance.on_load()

    @staticmethod
    def on_unload(plugin: Plugin) -> None:
        if hasattr(plugin.instance, 'on_unload'):
            plugin.instance.on_unload()

    @staticmethod
    def on_update(plugin: Plugin, old_version: str) -> None:
        if hasattr(plugin.instance, 'on_update'):
            plugin.instance.on_update(old_version)


# ============ 插件管理器（核心） ============

class PluginManager:
    """插件化框架核心管理器"""

    def __init__(self):
        self._plugins: Dict[str, Plugin] = {}
        self._resolver = DependencyResolver()
        self._loader = PluginLoader()
        self._listeners: Dict[str, List[Callable]] = {
            'load': [], 'unload': [], 'update': [], 'error': []
        }

    def register_spec(self, spec: PluginSpec) -> None:
        """注册插件规格（不立即加载）"""
        plugin = Plugin(spec=spec, checksum=spec.get_checksum())
        self._plugins[spec.name] = plugin

    def load_all(self) -> None:
        """按依赖顺序加载所有插件"""
        # 过滤未加载的
        pending = {n: p for n, p in self._plugins.items() 
                   if p.state == PluginState.UNLOADED}

        order = self._resolver.resolve(pending)

        for name in order:
            self._load_plugin(name)

    def _load_plugin(self, name: str) -> None:
        """加载单个插件"""
        plugin = self._plugins[name]
        plugin.state = PluginState.LOADING

        try:
            plugin.instance = self._loader.load(plugin.spec)
            plugin.state = PluginState.LOADED
            plugin.load_time = time.time()
            LifecycleHooks.on_load(plugin)
            self._emit('load', plugin)
